mapper.select:
select DATE_FORMAT(tr.TS, '%Y-%m-%d %H:%i') as ts, tr.VALUE as value
from TB_RAWDATA tr, TB_CTR_PRF_PUMPMST_INF tcppi
WHERE
tr.TAGNAME = tcppi.PRI_T_TAG
	AND
	tcppi.PUMP_GRP = #{pump_grp}

		and tr.TS <= #{startDate}
		and tr.TS > DATE_SUB(#{startDate}, INTERVAL #{cycle} minute)
		order by tr.TS desc limit 1;


		and tr.TS < #{startDate}
		and tr.TS >= DATE_SUB(#{startDate}, INTERVAL #{range} hour)
		and MINUTE(tr.TS) % #{cycle} = 0
		group by tr.TS
		order by tr.TS;

select DATE_FORMAT(tr.TS, '%Y-%m-%d %H:%i') as ts, tr.VALUE as value
from TB_RAWDATA tr, TB_CTR_PRF_PUMPMST_INF tcppi
WHERE
tr.TAGNAME = tcppi.LEI_TAG

	and tr.TS <= #{startDate}
	and tr.TS > DATE_SUB(#{startDate}, INTERVAL #{cycle} minute)
	order by tr.TS desc limit 1;


	and tr.TS < #{startDate}
	and tr.TS >= DATE_SUB(#{startDate}, INTERVAL #{range} hour)
	and MINUTE(tr.TS) % #{cycle} = 0
	group by tr.TS
	order by tr.TS;

select DATE_FORMAT(tr.TS, '%Y-%m-%d %H:%i') as ts, tr.VALUE as value
from TB_RAWDATA tr, TB_CTR_PRF_PUMPMST_INF tcppi
WHERE
tr.TAGNAME = tcppi.FRI_TAG
	AND
	tcppi.PUMP_GRP = #{pump_grp}

		and tr.TS <= #{startDate}
		and tr.TS > DATE_SUB(#{startDate}, INTERVAL #{cycle} minute)
		order by tr.TS desc limit 1;


		and tr.TS < #{startDate}
		and tr.TS >= DATE_SUB(#{startDate}, INTERVAL #{range} hour)
		and MINUTE(tr.TS) % #{cycle} = 0
		group by tr.TS
		order by tr.TS;

SELECT tr_spi.TS, tcppi.PUMP_TYP as PUMP_TYP, tr_spi.TAGNAME AS spi_tagname, tr_pmb.TAGNAME AS pmb_tagname, tr_spi.VALUE AS pump_freq, tr_pmb.VALUE AS pump_use, tcppi.PUMP_IDX, tcppi.PUMP_GRP_IDX, tcppi.PUMP_GRP_NM, tcppi.PUMP_NM FROM TB_CTR_PRF_PUMPMST_INF tcppi LEFT JOIN TB_RAWDATA tr_spi ON tr_spi.TAGNAME = tcppi.SPI_TAG AND tr_spi.TS = (select max(TS) from TB_RAWDATA where TS <= #{startDate} and TS > DATE_SUB(#{startDate}, interval 10 minute)) LEFT JOIN TB_RAWDATA tr_pmb ON tr_pmb.TAGNAME = tcppi.PMB_TAG AND tr_pmb.TS = (select max(TS) from TB_RAWDATA where TS <= #{startDate} and TS > DATE_SUB(#{startDate}, interval 10 minute))
WHERE tcppi.PUMP_GRP = #{pump_grp}
ORDER BY tcppi.PUMP_IDX;

SELECT tctr.DSTRB_ID as junction_id, tctr.PRDCT_VALUE as value, DATE_FORMAT(tctr.RGSTR_TIME, '%Y-%m-%d %H:%i') as ts from TB_CTR_TNK_RST tctr WHERE UPPER(tctr.DSTRB_ID) = UPPER(#{DSTRB_ID}) and
RGSTR_TIME <= DATE_ADD(#{startDate}, INTERVAL 1 minute) and RGSTR_TIME > DATE_SUB(#{startDate}, INTERVAL 5 minute) order by tctr.RGSTR_TIME desc limit 1
tctr.RGSTR_TIME <= #{startDate}
tctr.RGSTR_TIME <= #{startDate}
and tctr.RGSTR_TIME >= DATE_SUB(#{startDate}, INTERVAL #{range} hour) and MINUTE(tctr.RGSTR_TIME) % #{cycle} = 0 group by tctr.RGSTR_TIME order by tctr.RGSTR_TIME

SELECT tr.TS, tr.VALUE as value, tnt.PRI_TAG as tag, tnt.DSTRB_P_ID as dstrb_id from TB_RAWDATA tr LEFT JOIN TB_CTR_TNK_INF tnt ON tnt.PRI_TAG = tr.TAGNAME WHERE tnt.DSTRB_P_ID in
#{id}
AND tr.TS <= #{startDate} AND tr.TS >= DATE_SUB(#{startDate}, INTERVAL 12 hour) AND MINUTE(tr.TS) % 5 = 0 order by tr.TS;

SELECT tr.TS, tr.TAGNAME as tag, tr.VALUE as value FROM TB_RAWDATA tr WHERE tr.TAGNAME in
#{tag}
AND tr.TS <= #{startDate} AND tr.TS >= DATE_SUB(#{startDate}, INTERVAL 12 hour) AND MINUTE(tr.TS) % 5 = 0 order by tr.TS;

SELECT tr.TS, tr.VALUE as value
FROM TB_RAWDATA tr
WHERE tr.TAGNAME IN (
SELECT FRI_TAG
FROM TB_CTR_PRF_PUMPMST_INF
WHERE PUMP_GRP = #{pump_grp}
)
AND tr.TS BETWEEN DATE_SUB(#{startDate}, INTERVAL 12 HOUR) AND #{startDate}
AND MINUTE(tr.TS) % 5 = 0
GROUP BY tr.TS
ORDER BY tr.TS;

SELECT sum(tr.VALUE) as value from TB_CTR_TNK_INF tcti join TB_RAWDATA tr on tcti.FRI_TAG = tr.TAGNAME WHERE UPPER(tcti.DSTRB_Q_ID) in
UPPER(#{id})
and tr.TS <= #{startDate} and tr.TS > DATE_SUB(#{startDate}, INTERVAL 5 minute) group by tr.TS order by tr.TS desc limit 1;
and tr.TS < DATE_SUB(#{startDate}, INTERVAL #{cycle} minute) and tr.TS >= DATE_SUB(#{startDate}, INTERVAL #{range} hour) and MINUTE(tr.TS) % #{cycle} = 0 group by tr.TS order by tr.TS;

mapper.insert:
INSERT INTO TB_CTR_PUMPYN_RST ( OPT_IDX, PUMP_GRP, PUMP_IDX, PUMP_TYP, PUMP_YN, FREQ, RGSTR_TIME, PRDCT_MEAN, TUBE_PRSR_PRDCT, PWR_PRDCT
,CHNG_STTS
) VALUES ( #{opt_idx}, #{PUMP_GRP}, #{PUMP_IDX}, #{PUMP_TYP}, #{pump_yn}, #{freq}, #{ts}, #{flow}, #{pressure}, #{pwrPrdct}
,#{chng_stts}
) ON DUPLICATE KEY UPDATE PUMP_YN = #{pump_yn}, PUMP_TYP = #{PUMP_TYP}, PRDCT_MEAN = #{flow}, TUBE_PRSR_PRDCT = #{pressure}, PWR_PRDCT = #{pwrPrdct}, FREQ = #{freq}
,CHNG_STTS = #{chng_stts} ;

INSERT INTO TB_CTR_PUMPYN_INQUIRY ( OPT_IDX, PUMP_GRP, PUMP_IDX, PUMP_TYP, PUMP_YN, FREQ, RATE_CTGRY, FLOW_CTR, RGSTR_TIME, PRDCT_MEAN, TUBE_PRSR_PRDCT, PWR_PRDCT
,CHNG_STTS
) VALUES ( #{opt_idx}, #{PUMP_GRP}, #{PUMP_IDX}, #{PUMP_TYP}, #{pump_yn}, #{freq}, #{RATE_CTGRY}, #{FLOW_CTR}, #{ts}, #{flow}, #{pressure}, #{pwrPrdct}
,#{chng_stts}
) ON DUPLICATE KEY UPDATE PUMP_YN = #{pump_yn}, RATE_CTGRY = #{RATE_CTGRY}, FLOW_CTR = #{FLOW_CTR}, PUMP_TYP = #{PUMP_TYP}, PRDCT_MEAN = #{flow}, TUBE_PRSR_PRDCT = #{pressure}, PWR_PRDCT = #{pwrPrdct}, FREQ = #{freq}
,CHNG_STTS = #{chng_stts} ;

mapper.delete:
DELETE FROM TB_CTR_PUMPYN_INQUIRY
WHERE
RGSTR_TIME >= #{startDate}
AND
RGSTR_TIME <= #{endDate}

mapper.select:
SELECT COALESCE(inquiry.PUMP_GRP, rst.PUMP_GRP) AS PUMP_GRP, DATE_FORMAT(rst.RGSTR_TIME, '%Y-%m-%d %H:%i') as ts, COALESCE(inquiry.PUMP_IDX, rst.PUMP_IDX) AS PUMP_IDX, COALESCE(inquiry.PUMP_TYP, rst.PUMP_TYP) AS PUMP_TYP, COALESCE(inquiry.PUMP_YN, rst.PUMP_YN) AS PUMP_YN, COALESCE(inquiry.FREQ, rst.FREQ) AS FREQ FROM TB_CTR_PUMPYN_RST AS rst LEFT JOIN TB_CTR_PUMPYN_INQUIRY AS inquiry ON rst.OPT_IDX = inquiry.OPT_IDX AND rst.PUMP_IDX = inquiry.PUMP_IDX AND rst.PUMP_GRP = inquiry.PUMP_GRP WHERE
rst.RGSTR_TIME = (select max(RGSTR_TIME) from TB_CTR_PUMPYN_RST where RGSTR_TIME <= DATE_ADD(#{startDate}, interval 1 minute) and RGSTR_TIME > DATE_SUB(#{startDate}, interval 10 minute))
rst.RGSTR_TIME <= #{startDate} AND rst.RGSTR_TIME >= DATE_SUB(#{startDate}, INTERVAL #{range} hour) AND MINUTE(rst.RGSTR_TIME) % #{cycle} = 0
AND rst.PUMP_GRP = #{pump_grp}
ORDER BY rst.RGSTR_TIME, COALESCE(inquiry.PUMP_GRP, rst.PUMP_GRP) ASC, COALESCE(inquiry.PUMP_IDX, rst.PUMP_IDX) ASC;

SELECT COALESCE(inquiry.PUMP_GRP, rst.PUMP_GRP) AS PUMP_GRP, DATE_FORMAT(rst.RGSTR_TIME, '%Y-%m-%d %H:%i') as ts, COALESCE(inquiry.PUMP_IDX, rst.PUMP_IDX) AS PUMP_IDX, COALESCE(inquiry.PUMP_TYP, rst.PUMP_TYP) AS PUMP_TYP, COALESCE(inquiry.PUMP_YN, rst.PUMP_YN) AS PUMP_YN, COALESCE(inquiry.FREQ, rst.FREQ) AS FREQ, COALESCE(inquiry.PWR_PRDCT, rst.PWR_PRDCT) AS PWR_PRDCT, CASE WHEN inquiry.OPT_IDX IS NOT NULL THEN 1 ELSE 0 END AS flag, inquiry.FLOW_CTR as FLOW_CTR FROM TB_CTR_PUMPYN_RST AS rst LEFT JOIN TB_CTR_PUMPYN_INQUIRY AS inquiry ON rst.OPT_IDX = inquiry.OPT_IDX AND rst.PUMP_IDX = inquiry.PUMP_IDX and rst.PUMP_GRP = inquiry.PUMP_GRP WHERE
rst.PUMP_GRP = #{pump_grp} AND
rst.RGSTR_TIME = (select max(RGSTR_TIME) from TB_CTR_PUMPYN_RST where RGSTR_TIME <= DATE_ADD(#{startDate}, interval 1 minute) and RGSTR_TIME > DATE_SUB(#{startDate}, interval 10 minute)) GROUP BY rst.PUMP_IDX ORDER BY rst.RGSTR_TIME, COALESCE(inquiry.PUMP_IDX, rst.PUMP_IDX) ASC;

SELECT CAST(COALESCE(t2.PUMP_YN, t1.PUMP_YN) as INT) AS value FROM TB_CTR_PUMPYN_RST t1 LEFT JOIN TB_CTR_PUMPYN_INQUIRY t2 ON t1.OPT_IDX = t2.OPT_IDX AND t1.PUMP_IDX = t2.PUMP_IDX AND t1.RGSTR_TIME = t2.RGSTR_TIME WHERE t1.PUMP_IDX = #{pump_idx} AND t1.RGSTR_TIME <= DATE_SUB(#{startDate}, INTERVAL 1 minute)
and t1.RGSTR_TIME >= DATE_SUB(#{startDate}, INTERVAL 35 minute) order by t1.RGSTR_TIME desc limit 30;
and t1.RGSTR_TIME >= DATE_SUB(#{startDate}, INTERVAL 125 minute) order by t1.RGSTR_TIME desc limit 60;
and t1.RGSTR_TIME >= DATE_SUB(#{startDate}, INTERVAL 125 minute) order by t1.RGSTR_TIME desc limit 120;
and t1.RGSTR_TIME >= DATE_SUB(#{startDate}, INTERVAL 65 minute) order by t1.RGSTR_TIME desc limit 60;
and t1.RGSTR_TIME >= DATE_SUB(#{startDate}, INTERVAL 125 minute) order by t1.RGSTR_TIME desc limit 120;
and t1.RGSTR_TIME >= DATE_SUB(#{startDate}, INTERVAL #{interval} minute) order by t1.RGSTR_TIME desc limit #{limit};

SELECT GROUP_CONCAT( CASE WHEN tr.VALUE = 1 AND tr.TAGNAME = tc.PMB_TAG THEN tc.PUMP_IDX END ORDER BY tc.PUMP_IDX ASC SEPARATOR ',' ) AS PUMP_USE_RST, GROUP_CONCAT( CASE WHEN tr.TAGNAME = tc.SPI_TAG AND ROUND(tr.VALUE) != 0 THEN ROUND(tr.VALUE) END ORDER BY tc.PUMP_IDX ASC SEPARATOR ',' ) AS SPI_USE_RST FROM TB_RAWDATA tr JOIN TB_CTR_PRF_PUMPMST_INF tc ON tr.TAGNAME = tc.PMB_TAG OR tr.TAGNAME = tc.SPI_TAG WHERE tr.TS = (select max(TS) from TB_RAWDATA where TS <= #{targetDate} and TS > DATE_SUB(#{targetDate}, interval 10 minute))
AND tc.PUMP_GRP = #{pump_grp}
GROUP BY tr.TS;

SELECT GROUP_CONCAT(CASE WHEN A.PUMP_YN = 1 THEN A.PUMP_IDX END ORDER BY A.PUMP_IDX ASC) AS PUMP_USE_RST, GROUP_CONCAT(CASE WHEN A.FREQ != 0 THEN ROUND(A.FREQ) END ORDER BY A.FREQ ASC) AS SPI_USE_RST FROM ( SELECT t1.PUMP_IDX, COALESCE(t2.PUMP_YN, t1.PUMP_YN) AS PUMP_YN, COALESCE(t2.RGSTR_TIME, t1.RGSTR_TIME) AS RGSTR_TIME, COALESCE(t2.FREQ, t1.FREQ) AS FREQ FROM TB_CTR_PUMPYN_RST t1 LEFT JOIN TB_CTR_PUMPYN_INQUIRY t2 ON t1.OPT_IDX = t2.OPT_IDX AND t1.PUMP_IDX = t2.PUMP_IDX AND t1.RGSTR_TIME = t2.RGSTR_TIME WHERE
t1.PUMP_GRP = #{pump_grp} AND
t1.RGSTR_TIME = (select max(RGSTR_TIME) from TB_CTR_PUMPYN_RST where RGSTR_TIME <= DATE_SUB(#{targetDate}, interval 1 minute) and RGSTR_TIME > DATE_SUB(#{targetDate}, interval 30 minute)) ) A GROUP BY A.RGSTR_TIME;

SELECT i.TS, GROUP_CONCAT(DISTINCT CASE WHEN tr.VALUE = 1 THEN tc.PUMP_IDX END ORDER BY tc.PUMP_IDX ASC) AS PUMP_YN_RST FROM A i LEFT JOIN TB_RAWDATA tr ON i.TS = tr.TS JOIN TB_CTR_PRF_PUMPMST_INF tc ON tr.TAGNAME = tc.PMB_TAG WHERE 1 = 1
AND tc.PUMP_GRP = #{pump_grp}
OR tr.TS IS NULL GROUP BY i.TS ORDER BY i.TS

SELECT DATE_FORMAT(RGSTR_TIME, '%Y-%m-%d %H:%i') AS RGSTR_TIME, NewPumpComb, NewPumpFreq, AgoPumpComb, AgoPumpFreq FROM TB_MNL_CHN_LOG WHERE
RGSTR_TIME >= DATE_SUB(#{nowDate}, INTERVAL 60 MINUTE)
RGSTR_TIME >= DATE_SUB(#{nowDate}, INTERVAL 60 MINUTE)
RGSTR_TIME >= DATE_SUB(#{nowDate}, INTERVAL 60 MINUTE)
RGSTR_TIME >= DATE_SUB(#{nowDate}, INTERVAL 30 MINUTE)
AND RGSTR_TIME <= #{nowDate}
AND PUMP_GRP = #{pump_grp}
ORDER BY RGSTR_TIME DESC LIMIT 1;

SELECT GROUP_CONCAT(CASE WHEN A.PUMP_YN = 1 THEN A.PUMP_IDX END ORDER BY A.PUMP_IDX ASC) AS PUMP_USE_RST, GROUP_CONCAT(CASE WHEN A.FREQ != 0 THEN ROUND(A.FREQ) END ORDER BY A.FREQ ASC) AS SPI_USE_RST, DATE_FORMAT(A.RGSTR_TIME, '%Y-%m-%d %H:%i') AS RGSTR_TIME, A.OPT_IDX AS OPT_IDX, CAST(A.TUBE_PRSR_PRDCT AS DOUBLE) AS TUBE_PRSR_PRDCT, CAST(A.PRDCT_MEAN AS DOUBLE) AS PRDCT_MEAN FROM ( SELECT t1.PUMP_IDX, COALESCE(t2.PUMP_YN, t1.PUMP_YN) AS PUMP_YN, COALESCE(t2.RGSTR_TIME, t1.RGSTR_TIME) AS RGSTR_TIME, COALESCE(t2.FREQ, t1.FREQ) AS FREQ, COALESCE(t2.OPT_IDX, t1.OPT_IDX) AS OPT_IDX, COALESCE(t2.TUBE_PRSR_PRDCT, t1.TUBE_PRSR_PRDCT) AS TUBE_PRSR_PRDCT, COALESCE(t2.PRDCT_MEAN, t1.PRDCT_MEAN) AS PRDCT_MEAN FROM TB_CTR_PUMPYN_RST t1 LEFT JOIN TB_CTR_PUMPYN_INQUIRY t2 ON t1.OPT_IDX = t2.OPT_IDX AND t1.PUMP_IDX = t2.PUMP_IDX AND t1.RGSTR_TIME = t2.RGSTR_TIME WHERE
t1.PUMP_GRP = #{pump_grp} AND
t1.RGSTR_TIME = (select max(RGSTR_TIME) from TB_CTR_PUMPYN_RST where RGSTR_TIME <= #{targetDate} and RGSTR_TIME > DATE_SUB(#{targetDate}, interval 10 minute)) ) A GROUP BY A.RGSTR_TIME;

mapper.insert:
INSERT INTO TB_MNL_CHN_LOG
	(RGSTR_TIME, OPER, PUMP_GRP)
VALUES(
	#{nowDate},
	#{oper},
	#{pump_grp}
);

mapper.select:
UPDATE
	TB_WPP_TAG_CODE
SET
	TAG_DSC= #{nowDate}
WHERE
	FUNC_TYP = #{func_typ};

SELECT PUMP_GRP, FRI_TAG, PRI_T_TAG FROM TB_CTR_PRF_PUMPMST_INF
WHERE PUMP_GRP = #{pump_grp}
GROUP BY PUMP_GRP;

mapper.insert:
UPDATE
TB_PUMP_COMBINATION
SET
PUMP_YN= #{PUMP_YN}
WHERE
PUMP_GRP= #{PUMP_GRP}
AND
PUMP_IDX = #{PUMP_IDX}
AND
PUMP_COUNT = #{PUMP_COUNT}
AND
PUMP_PRIORITY = #{PUMP_PRIORITY};

mapper.select:
SELECT PUMP_GRP, COMB_NAME, PUMP_COUNT, PUMP_PRIORITY, PUMP_PRIORITY_DCS, PUMP_RULES, USE_YN FROM TB_PUMP_COMBINATION_INF
WHERE PUMP_GRP = #{pump_grp}
ORDER BY PUMP_COUNT, PUMP_PRIORITY

mapper.update:
UPDATE
TB_PUMP_COMBINATION_INF
SET
USE_YN = #{use_yn}
WHERE
PUMP_GRP = #{use_yn}
AND PUMP_COUNT = #{use_yn}
AND PUMP_PRIORITY = #{pump_priority}

mapper.select:
SELECT
*
FROM
TB_PUMP_CAL
WHERE
PUMP_GRP = #{pump_grp}
AND
PUMP_COUNT = #{pump_count}
AND
PUMP_PRIORITY = #{pump_priority}
ORDER BY
C_IDX, PUMP_COUNT, PUMP_PRIORITY, COUNT_IDX;

mapper.update:
UPDATE TB_PUMP_COMBINATION_INF
SET USE_YN = #{USE_YN}
WHERE
PUMP_GRP = #{PUMP_GRP}
AND
PUMP_COUNT = #{PUMP_COUNT}
AND
PUMP_PRIORITY = #{PUMP_PRIORITY}

UPDATE TB_PUMP_CAL
SET USE_YN = 0
WHERE
PUMP_GRP = #{PUMP_GRP}
AND
C_IDX = #{C_IDX}
AND
PUMP_COUNT = #{PUMP_COUNT}
AND
PUMP_PRIORITY = #{PUMP_PRIORITY};

UPDATE TB_PUMP_CAL
SET USE_YN = 1
WHERE
PUMP_GRP = #{PUMP_GRP}
AND
C_IDX = #{C_IDX}
AND
PUMP_COUNT = #{PUMP_COUNT}
AND
PUMP_PRIORITY = #{PUMP_PRIORITY}
AND
COUNT_IDX = #{COUNT_IDX};
